import { Router } from "express";
import { forgotPasswordSendOtpController, forgotPasswordVerifyOtpController, loginController, logoutController, meController, refreshController, registerController, resetPasswordController } from "../controllers/auth.controller.js";
import { requireAuth } from "../middlewares/auth.js";
import { validate } from "../middlewares/validate.js";
import { forgotPasswordSendOtpSchema, forgotPasswordVerifyOtpSchema, loginSchema, registerSchema, resetPasswordSchema } from "../validations/auth.validation.js";
export const authRouter = Router();
authRouter.post("/register", validate(registerSchema), registerController);
authRouter.post("/login", validate(loginSchema), loginController);
authRouter.post("/forgot-password/send-otp", validate(forgotPasswordSendOtpSchema), forgotPasswordSendOtpController);
authRouter.post("/forgot-password/verify-otp", validate(forgotPasswordVerifyOtpSchema), forgotPasswordVerifyOtpController);
authRouter.post("/forgot-password/reset", validate(resetPasswordSchema), resetPasswordController);
authRouter.post("/refresh", refreshController);
authRouter.get("/me", requireAuth, meController);
authRouter.post("/logout", requireAuth, logoutController);
